// ============================================
// NODO: Extract Body HTML - CON SOPORTE MULTI-URL
// ============================================

const cheerio = require('cheerio');

const KEYWORDS = [
  'tasa', 'tasas', 'crédito', 'credito', 'vehículo', 'vehiculo',
  'automóvil', 'automovil', 'carro', 'moto', 'motocicleta',
  'usado', 'nuevo', 'modelo', 'financiación', 'financiacion',
  'plazo', 'cuota', 'monto', 'desde', 'hasta', 'fija', 'variable',
  'interés', 'interes', 'ea', 'efectivo anual', 'seguro', 'prenda',
  'garantía', 'garantia', 'mensual', 'porcentaje'
];

// Regex para detectar porcentajes (ej: 11.95%, UVR + 6.50%, E.A.)
const RATE_REGEX = /\d+[.,]\d+\s*%|E\.?A\.?|N\.?M\.?V|UVR/i;

const HEADERS = {
  'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
  'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
  'Accept-Language': 'es-ES,es;q=0.9,en;q=0.8'
};

function cleanText(text) {
  return text.replace(/\s+/g, ' ').trim();
}

function hasRateData(text) {
  return RATE_REGEX.test(text);
}

function isRelevant(text) {
  if (!text) return false;
  // Capturar textos cortos si contienen porcentajes/tasas
  if (text.length >= 5 && hasRateData(text)) return true;
  if (text.length < 10) return false;
  const lowerText = text.toLowerCase();
  return KEYWORDS.some(keyword => lowerText.includes(keyword));
}

function extractFromHtml(htmlStr) {
  const $ = cheerio.load(htmlStr);
  $('script, style, noscript, iframe, form').remove();

  const tables = [];
  $('table').each((i, table) => {
    const tableText = $(table).text();
    if (isRelevant(tableText)) {
      const rows = [];
      $(table).find('tr').each((j, row) => {
        const cells = [];
        $(row).find('td, th').each((k, cell) => {
          const cellText = cleanText($(cell).text());
          if (cellText) cells.push(cellText);
        });
        if (cells.length > 0) rows.push(cells.join(' | '));
      });
      if (rows.length > 0) tables.push(rows.join('\n'));
    }
  });

  // Extraer contenido de headings + paragraphs + divs + spans
  const relevantParagraphs = [];
  const seen = new Set();

  // Primero: capturar headings con contexto (heading + siguiente sibling)
  $('h1, h2, h3, h4').each((i, heading) => {
    const headText = cleanText($(heading).text());
    if (!headText || headText.length < 3) return;
    // Obtener el texto del siguiente hermano para dar contexto
    const nextSibling = $(heading).next();
    const nextText = nextSibling.length ? cleanText(nextSibling.text()) : '';
    // Si el heading o su contexto son relevantes, capturar ambos
    if (isRelevant(headText) || isRelevant(nextText) || hasRateData(headText)) {
      const combined = nextText ? `${headText}: ${nextText}` : headText;
      if (!seen.has(combined) && combined.length < 1000) {
        seen.add(combined);
        relevantParagraphs.push(combined);
      }
    }
  });

  // Segundo: capturar secciones/cards completas que contengan tasas
  $('[class*="card"], [class*="grid"], [class*="rate"], [class*="tasa"], [class*="product"], section, article').each((i, container) => {
    const text = cleanText($(container).text());
    if (text.length > 15 && text.length < 2000 && hasRateData(text)) {
      if (!seen.has(text)) {
        seen.add(text);
        relevantParagraphs.push(text);
      }
    }
  });

  // Tercero: capturar elementos individuales relevantes
  $('p, div, span, li, td, th, h1, h2, h3, h4').each((i, elem) => {
    const text = cleanText($(elem).text());
    // Capturar textos con porcentajes aunque sean cortos (>= 5 chars)
    if (hasRateData(text) && text.length >= 5 && text.length < 500) {
      if (!seen.has(text)) {
        seen.add(text);
        relevantParagraphs.push(text);
      }
    }
    // Capturar textos relevantes por keywords
    if (text.length > 20 && text.length < 1000 && isRelevant(text)) {
      if (!seen.has(text)) {
        seen.add(text);
        relevantParagraphs.push(text);
      }
    }
  });

  const lists = [];
  $('ul, ol').each((i, list) => {
    const listText = cleanText($(list).text());
    if ((isRelevant(listText) || hasRateData(listText)) && listText.length > 20) {
      const items = [];
      $(list).find('li').each((j, item) => {
        const itemText = cleanText($(item).text());
        if (itemText.length > 5) items.push('• ' + itemText);
      });
      if (items.length > 0) lists.push(items.join('\n'));
    }
  });

  const headings = [];
  const pageTitle = $('title').text().trim();
  $('h1, h2, h3, h4').each((i, heading) => {
    const text = cleanText($(heading).text());
    const tagName = $(heading).prop('tagName');
    const level = parseInt(tagName.replace('H', ''));
    if (text && text.length > 3) headings.push({ level, text });
  });

  return { tables, relevantParagraphs, lists, headings, pageTitle };
}

// Procesar HTML principal
const html = $input.first().json.data || $input.first().json || '';
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);
const mainResult = extractFromHtml(htmlStr);

// Procesar URLs adicionales si existen
const extraUrlsStr = $('Add Protocol To Domain').first().json.extra_urls || '';
const extraResults = [];

if (extraUrlsStr.trim()) {
  const extraUrls = extraUrlsStr.split(',').map(u => u.trim()).filter(u => u);
  for (const url of extraUrls) {
    try {
      console.log(`Fetching extra URL: ${url}`);
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000);
      const response = await fetch(url, { headers: HEADERS, signal: controller.signal });
      clearTimeout(timeoutId);
      const responseText = await response.text();
      const result = extractFromHtml(responseText);
      extraResults.push(result);
      console.log(`Extra URL OK: ${result.tables.length} tables, ${result.relevantParagraphs.length} paragraphs`);
    } catch (err) {
      console.log(`Extra URL failed (${url}): ${err.message}`);
    }
  }
}

// Combinar resultados de todas las URLs
const allTables = [...mainResult.tables, ...extraResults.flatMap(r => r.tables)];
const allParagraphs = [...mainResult.relevantParagraphs, ...extraResults.flatMap(r => r.relevantParagraphs)];
const allLists = [...mainResult.lists, ...extraResults.flatMap(r => r.lists)];
const allHeadings = [...mainResult.headings, ...extraResults.flatMap(r => r.headings)];

// Deduplicar párrafos
const uniqueParagraphs = [...new Set(allParagraphs)];

// Incluir headings formateados en el contenido para que el LLM los vea
const headingsText = allHeadings
  .slice(0, 20)
  .map(h => `${'#'.repeat(h.level)} ${h.text}`)
  .join('\n');

const optimizedText = [
  headingsText,
  ...uniqueParagraphs.slice(0, 50),
  ...allLists.slice(0, 10)
].filter(Boolean).join('\n\n');

const tablesText = allTables.slice(0, 10).join('\n---\n');

return {
  json: {
    type: 'body_content',
    title: mainResult.pageTitle,
    headings: allHeadings.slice(0, 20),
    tables: tablesText,
    relevant_content: optimizedText,
    stats: {
      tables_found: allTables.length,
      paragraphs_found: uniqueParagraphs.length,
      lists_found: allLists.length,
      extra_urls_processed: extraResults.length
    }
  }
};

// ============================================
// NODO: Optimize Context for LLM
// ============================================

const bodyData = $input.first().json;
const pageTitle = bodyData.title || '';
const headings = bodyData.headings || [];
const tables = bodyData.tables || '';
const relevantContent = bodyData.relevant_content || '';
const stats = bodyData.stats || {};

const bankName = pageTitle.includes('-')
  ? pageTitle.split('-').pop().trim()
  : pageTitle.includes('|')
    ? pageTitle.split('|').pop().trim()
    : pageTitle;

const headingsText = headings
  .filter(h => h.level <= 2)
  .map(h => `${'#'.repeat(h.level)} ${h.text}`)
  .join('\n');

const sections = [];
sections.push(`# BANCO: ${bankName}`);
if (headingsText) sections.push(`## Estructura\n${headingsText}`);
if (tables && tables.trim()) sections.push(`## Tablas de Tasas\n${tables}`);
if (relevantContent && relevantContent.trim()) {
  const truncatedContent = relevantContent.length > 8000
    ? relevantContent.substring(0, 8000) + '...'
    : relevantContent;
  sections.push(`## Información Relevante\n${truncatedContent}`);
}

const compactContext = sections.join('\n\n');
const optimizedSize = compactContext.length;

return {
  json: {
    metadata: {
      extraction_date: new Date().toISOString(),
      page_title: pageTitle,
      bank_name: bankName,
      optimized: true
    },
    compact_context: compactContext,
    optimization_stats: {
      tables_found: stats.tables_found || 0,
      paragraphs_found: stats.paragraphs_found || 0,
      final_chars: optimizedSize,
      estimated_tokens: Math.ceil(optimizedSize / 4)
    }
  }
};

