// Fix MIME type for PDFs downloaded from Google Drive
// Google Drive returns application/octet-stream instead of application/pdf
const items = $input.all();
for (const item of items) {
  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      const bin = item.binary[key];
      if (bin.mimeType === 'application/octet-stream') {
        const fileName = (bin.fileName || '').toLowerCase();
        if (fileName.endsWith('.pdf') || $('Add Protocol To Domain').item.json.pdf_url.toLowerCase().includes('.pdf') || $('Add Protocol To Domain').item.json.pdf_url.includes('drive.google.com')) {
          bin.mimeType = 'application/pdf';
        }
      }
    }
  }
}
return items;

// ============================================
// NODO: Validate & Parse Response - CRÉDITOS DE VEHÍCULO
// ============================================

const llmResponse = $input.first().json;

let jsonText = '';
if (
  llmResponse &&
  llmResponse.output &&
  Array.isArray(llmResponse.output) &&
  llmResponse.output[0]?.content?.[0]?.text
) {
  jsonText = llmResponse.output[0].content[0].text;
} else {
  throw new Error('Formato de respuesta OpenAI no reconocido');
}

jsonText = jsonText
  .replace(/\`\`\`json\n?/g, '')
  .replace(/\`\`\`\n?/g, '')
  .trim();

const arrayMatch = jsonText.match(/\[\s*\{[\s\S]*\}\s*\]/);
if (arrayMatch) {
  jsonText = arrayMatch[0];
}

let cleanData;
try {
  cleanData = JSON.parse(jsonText);
} catch (error) {
  throw new Error('Error parsing JSON: ' + error.message + '\nTexto: ' + jsonText.substring(0, 500));
}

if (!Array.isArray(cleanData)) {
  if (typeof cleanData === 'object' && cleanData !== null) {
    cleanData = [cleanData];
  } else {
    throw new Error('La respuesta no es un array o objeto válido');
  }
}

// ============================================
// VALIDACIÓN Y NORMALIZACIÓN - VEHÍCULOS
// ============================================
const VALID_VEHICLE_TYPE = ['Nuevo', 'Usado', 'Ambos'];
const VALID_VEHICLE_CATEGORY = ['Automóvil', 'Moto', 'Ambos'];
const CREDIT_TYPE = 'Crédito de vehículo';
const RATE_TYPE = 'Tasa efectiva anual';

const validated = cleanData
  .filter(item => {
    if (!item.bank || (!item.rate && !item.rate_range)) return false;
    const ct = (item.credit_type || '').toLowerCase();
    // Rechazar productos que NO sean de vehículo
    if (ct.includes('hipotecario') || ct.includes('vivienda') ||
        ct.includes('consumo') || ct.includes('libranza') ||
        ct.includes('tarjeta') || ct.includes('leasing')) {
      return false;
    }
    return true;
  })
  .map(item => {
    item.credit_type = CREDIT_TYPE;
    item.rate_type = RATE_TYPE;
    item.rate_denomination = 'Pesos';

    // Normalizar vehicle_type
    let vt = (item.vehicle_type || '').trim();
    const vtLower = vt.toLowerCase();
    if (vtLower.includes('nuevo') || vtLower === 'new') {
      vt = 'Nuevo';
    } else if (vtLower.includes('usado') || vtLower === 'used') {
      vt = 'Usado';
    } else if (vtLower.includes('ambos') || vtLower.includes('aplica')) {
      vt = 'Ambos';
    }
    if (!VALID_VEHICLE_TYPE.includes(vt)) vt = 'Ambos';
    item.vehicle_type = vt;

    // Normalizar vehicle_category
    let vc = (item.vehicle_category || '').trim();
    const vcLower = vc.toLowerCase();
    if (vcLower.includes('auto') || vcLower.includes('carro') || vcLower.includes('camioneta')) {
      vc = 'Automóvil';
    } else if (vcLower.includes('moto')) {
      vc = 'Moto';
    } else if (vcLower.includes('ambos') || vcLower.includes('aplica')) {
      vc = 'Ambos';
    }
    if (!VALID_VEHICLE_CATEGORY.includes(vc)) vc = 'Ambos';
    item.vehicle_category = vc;

    // Normalizar rate
    let rate = (item.rate || '').trim();
    rate = rate.replace(/(\d),(\d)/g, '$1.$2');
    if (rate && !rate.includes('%')) rate += '%';
    item.rate = rate;

    // Normalizar payment_type
    if (item.payment_type) {
      const pt = item.payment_type.toLowerCase();
      if (pt.includes('fij')) item.payment_type = 'Cuota fija';
      else if (pt.includes('variabl')) item.payment_type = 'Cuota variable';
      else item.payment_type = null;
    }

    // Asegurar arrays
    if (item.conditions && !Array.isArray(item.conditions)) {
      item.conditions = [String(item.conditions)];
    }
    if (item.requirements && !Array.isArray(item.requirements)) {
      item.requirements = [String(item.requirements)];
    }

    // Convertir strings vacíos a null
    for (const key of Object.keys(item)) {
      if (item[key] === '' || item[key] === 'N/A' || item[key] === 'n/a') {
        item[key] = null;
      }
    }

    return item;
  });

if (validated.length === 0) {
  return [{
    json: {
      _error: true,
      _message: 'No se encontraron productos de vehículo válidos',
      _raw_response: jsonText.substring(0, 500)
    }
  }];
}

console.log('Productos vehículo válidos: ' + validated.length);
validated.forEach(v => console.log('  ' + v.bank + ' - ' + v.vehicle_type + ' - ' + v.vehicle_category + ': ' + v.rate));

return validated.map(item => ({ json: item }));

// ============================================
// NODO: Prepare For Output - CRÉDITOS DE VEHÍCULO
// Sin lógica UVR (vehículos solo usan Pesos)
// ============================================

const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0]._error) {
  console.log('Skipping bank - no valid products:', items[0]._message);
  return [];
}

const domainsNode = $('Add Protocol To Domain').first().json;
const page_url = domainsNode.finalUrl;
const pdf_url = domainsNode.pdf_url;

function normalizeForId(text) {
  if (!text) return '';
  return text
    .toString()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '')
    .replace(/_+/g, '')
    .replace(/-+/g, '')
    .replace(/[^a-z0-9%.]/g, '')
    .trim();
}

function generateUniqueId(banco, tipoCredito, vehicleType, vehicleCategory) {
  const parts = [
    normalizeForId(banco),
    normalizeForId(tipoCredito),
    normalizeForId(vehicleType),
    normalizeForId(vehicleCategory),
  ].filter(p => p);
  return parts.join('__');
}

function obtenerFechaHoraColombia() {
  const opciones = { timeZone: 'America/Bogota', hour12: false };
  const fechaHora = new Date().toLocaleString('sv-SE', opciones).replace(' ', 'T');
  const [fecha, hora] = fechaHora.split('T');
  return { fecha, hora };
}

const { fecha, hora } = obtenerFechaHoraColombia();

let result = items.map(item => {
  const banco = item.bank || '';
  const tipoCredito = item.credit_type || 'Crédito de vehículo';
  const vehicleType = item.vehicle_type || 'Ambos';
  const vehicleCategory = item.vehicle_category || 'Ambos';
  const tasaTexto = item.rate || '';

  const idUnico = generateUniqueId(banco, tipoCredito, vehicleType, vehicleCategory);

  return {
    id_unico: idUnico,
    banco: banco,
    tipo_credito: tipoCredito,
    tipo_vivienda: '',
    denominacion: 'Pesos',
    tipo_tasa: item.rate_type || 'Tasa efectiva anual',
    tasa: tasaTexto,
    tasa_final: '',
    uvr_variacion_anual: '',
    tasa_minima: item.rate_range?.min || '',
    tasa_maxima: item.rate_range?.max || '',
    monto_minimo: item.min_amount || '',
    monto_maximo: item.max_amount || '',
    plazo_maximo: item.max_term || '',
    tipo_pago: item.payment_type || '',
    descripcion: item.description || '',
    condiciones: Array.isArray(item.conditions) ? item.conditions.join('; ') : (item.conditions || ''),
    requisitos: Array.isArray(item.requirements) ? item.requirements.join('; ') : (item.requirements || ''),
    descuento_nomina: item.additional_info?.descuento_nomina || '',
    beneficio_avaluo: item.additional_info?.seguro_obligatorio || '',
    fecha_extraccion: fecha,
    hora_extraccion: hora,
    url_pagina: page_url || '',
    url_pdf: pdf_url || ''
  };
});

const unique = {};
result.forEach(item => {
  if (!unique[item.id_unico]) {
    unique[item.id_unico] = item;
  }
});

return Object.values(unique).map(r => ({ json: r }));

// ============================================
// NODO: Execution Summary
// Resumen después de procesar todos los bancos
// ============================================

const allBanks = $('Filter Active Banks').all();
const totalBanks = allBanks.length;

const opciones = { timeZone: 'America/Bogota', hour12: false };
const fechaHora = new Date().toLocaleString('sv-SE', opciones).replace(' ', 'T');
const [fecha, hora] = fechaHora.split('T');

const summary = {
  execution_date: fecha,
  execution_time: hora,
  total_banks_processed: totalBanks,
  banks_list: allBanks.map(b => b.json.banco || b.json.url).join(', '),
  status: 'completed',
  message: `Scraping completado: ${totalBanks} bancos procesados el ${fecha} a las ${hora} (hora Colombia)`
};

console.log(summary.message);

return { json: summary };
